# --- Secure WSGI Middleware ---

class SecureSOAPMiddleware:
    """
    WSGI middleware that:
    1. Validates SOAPAction header against SOAP body to prevent spoofing
    2. Applies rate limiting
    3. Validates Content-Type
    4. Adds security headers to responses
    """

    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        # --- Rate Limiting ---
        client_ip = environ.get('REMOTE_ADDR', 'unknown')
        if not rate_limiter.is_allowed(client_ip):
            logger.warning(f"Rate limit exceeded for {client_ip}")
            return self._fault_response(
                start_response,
                'Server.RateLimitExceeded',
                'Too many requests. Please try again later.',
                status='429 Too Many Requests'
            )

        # --- Content-Type Validation ---
        content_type = environ.get('CONTENT_TYPE', '')
        if environ.get('REQUEST_METHOD') == 'POST':
            if 'text/xml' not in content_type and 'application/soap+xml' not in content_type:
                # Allow GET for WSDL retrieval
                if '?wsdl' not in environ.get('QUERY_STRING', '').lower():
                    logger.warning(f"Invalid Content-Type: {content_type}")
                    return self._fault_response(
                        start_response,
                        'Client.InvalidContentType',
                        'Content-Type must be text/xml or application/soap+xml'
                    )

            # --- SOAPAction Spoofing Prevention ---
            validation_result = validate_soapaction_against_body(environ)
            if validation_result is not True:
                logger.warning(f"SOAPAction validation failed: {validation_result}")
                return self._fault_response(
                    start_response,
                    'Client.SOAPActionMismatch',
                    validation_result
                )

        # --- Add Security Headers ---
        def secure_start_response(status, headers, exc_info=None):
            security_headers = [
                ('X-Content-Type-Options', 'nosniff'),
                ('X-Frame-Options', 'DENY'),
                ('Strict-Transport-Security', 'max-age=31536000; includeSubDomains'),
                ('Cache-Control', 'no-store, no-cache, must-revalidate'),
                ('Pragma', 'no-cache'),
            ]
            headers.extend(security_headers)
            return start_response(status, headers, exc_info)

        return self.app(environ, secure_start_response)

    def _fault_response(self, start_response, fault_code, fault_string, status='500 Internal Server Error'):
        """Generate a SOAP fault response."""
        from xml.sax.saxutils import escape
        fault_xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>{escape(fault_code)}</faultcode>
      <faultstring>{escape(fault_string)}</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>'''

        response_bytes = fault_xml.encode('utf-8')
        headers = [
            ('Content-Type', 'text/xml; charset=utf-8'),
            ('Content-Length', str(len(response_bytes))),
            ('X-Content-Type-Options', 'nosniff'),
            ('X-Frame-Options', 'DENY'),
        ]
        start_response(status, headers)
        return [response_bytes]


# Wrap the WSGI application with security middleware
secure_wsgi_application = SecureSOAPMiddleware(wsgi_application_base)


